import React, { useEffect, useRef, useState } from 'react';
import './FloatingLines.css';

const FloatingLines = ({
  linesGradient = ['#240632', '#6c05eb', '#8000ff'],
  animationSpeed = 2.2,
  interactive = true,
  bendRadius = 10,
  bendStrength = 0.8,
  mouseDamping = 0.14,
  parallax = true,
  parallaxStrength = 0.1,
}) => {
  const containerRef = useRef(null);
  const canvasRef = useRef(null);
  const [mousePos, setMousePos] = useState({ x: 0, y: 0 });
  const linesRef = useRef([]);

  useEffect(() => {
    const canvas = canvasRef.current;
    if (!canvas) return;

    const ctx = canvas.getContext('2d');
    let animationId;
    let time = 0;

    // Set canvas size
    const container = containerRef.current;
    canvas.width = container.clientWidth;
    canvas.height = container.clientHeight;

    // Initialize lines
    const initLines = () => {
      linesRef.current = [];
      const lineCount = 5;
      for (let i = 0; i < lineCount; i++) {
        linesRef.current.push({
          x: Math.random() * canvas.width,
          y: Math.random() * canvas.height,
          vx: (Math.random() - 0.5) * 2,
          vy: (Math.random() - 0.5) * 2,
          length: 50 + Math.random() * 100,
          angle: Math.random() * Math.PI * 2,
        });
      }
    };

    initLines();

    const getColor = (index) => {
      const colors = linesGradient;
      return colors[index % colors.length];
    };

    const drawLine = (line, index) => {
      const x = line.x;
      const y = line.y;
      const angle = line.angle;
      const length = line.length;

      // Create gradient for line
      const gradient = ctx.createLinearGradient(
        x - Math.cos(angle) * length / 2,
        y - Math.sin(angle) * length / 2,
        x + Math.cos(angle) * length / 2,
        y + Math.sin(angle) * length / 2
      );

      gradient.addColorStop(0, 'rgba(255, 255, 255, 0)');
      gradient.addColorStop(0.5, getColor(index));
      gradient.addColorStop(1, 'rgba(255, 255, 255, 0)');

      ctx.strokeStyle = gradient;
      ctx.lineWidth = 3;
      ctx.lineCap = 'round';

      ctx.beginPath();
      ctx.moveTo(
        x - Math.cos(angle) * length / 2,
        y - Math.sin(angle) * length / 2
      );
      ctx.lineTo(
        x + Math.cos(angle) * length / 2,
        y + Math.sin(angle) * length / 2
      );
      ctx.stroke();

      // Draw glow
      ctx.strokeStyle = getColor(index);
      ctx.globalAlpha = 0.2;
      ctx.lineWidth = 8;
      ctx.stroke();
      ctx.globalAlpha = 1;
    };

    const animate = () => {
      time += animationSpeed * 0.016;

      // Clear canvas
      ctx.fillStyle = 'rgba(0, 0, 0, 0.02)';
      ctx.fillRect(0, 0, canvas.width, canvas.height);

      // Update and draw lines
      linesRef.current.forEach((line, index) => {
        // Apply animation
        line.angle += 0.02 * animationSpeed;
        line.x += line.vx;
        line.y += line.vy;

        // Wrap around edges
        if (line.x < -50) line.x = canvas.width + 50;
        if (line.x > canvas.width + 50) line.x = -50;
        if (line.y < -50) line.y = canvas.height + 50;
        if (line.y > canvas.height + 50) line.y = -50;

        // Interactive mouse damping
        if (interactive) {
          const dx = mousePos.x - line.x;
          const dy = mousePos.y - line.y;
          const distance = Math.sqrt(dx * dx + dy * dy);
          const maxDistance = 200;

          if (distance < maxDistance) {
            const force = (1 - distance / maxDistance) * bendStrength;
            line.vx -= (dx / distance) * force * mouseDamping;
            line.vy -= (dy / distance) * force * mouseDamping;
          }
        }

        // Apply friction
        line.vx *= 0.98;
        line.vy *= 0.98;

        // Parallax effect
        if (parallax) {
          line.x += Math.sin(time * 0.5 + index) * parallaxStrength;
          line.y += Math.cos(time * 0.5 + index) * parallaxStrength;
        }

        drawLine(line, index);
      });

      animationId = requestAnimationFrame(animate);
    };

    animate();

    // Handle mouse move
    const handleMouseMove = (e) => {
      const rect = canvas.getBoundingClientRect();
      setMousePos({
        x: e.clientX - rect.left,
        y: e.clientY - rect.top,
      });
    };

    if (interactive) {
      canvas.addEventListener('mousemove', handleMouseMove);
    }

    // Handle window resize
    const handleResize = () => {
      canvas.width = container.clientWidth;
      canvas.height = container.clientHeight;
    };

    window.addEventListener('resize', handleResize);

    return () => {
      cancelAnimationFrame(animationId);
      if (interactive) {
        canvas.removeEventListener('mousemove', handleMouseMove);
      }
      window.removeEventListener('resize', handleResize);
    };
  }, [linesGradient, animationSpeed, interactive, bendRadius, bendStrength, mouseDamping, parallax, parallaxStrength, mousePos]);

  return (
    <div ref={containerRef} className="floating-lines-container">
      <canvas
        ref={canvasRef}
        className="floating-lines-canvas"
        style={{
          display: 'block',
          width: '100%',
          height: '100%',
        }}
      />
    </div>
  );
};

export default FloatingLines;
